module.render:
const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const raw = (sections[0] || '').toString();
const sep = (args.separator !== undefined && String(args.separator).length > 0) ? String(args.separator) : '+';
const size = (['sm', 'md', 'lg'].indexOf(String(args.size || 'md').toLowerCase()) >= 0) ? String(args.size || 'md').toLowerCase() : 'md';
const color = (args.color && String(args.color).trim()) || '';
const parts = raw.split('+').map(function (k) { return k.trim(); }).filter(function (k) { return k.length > 0; });
const cls = 'mdp-mod-shortcut' + (size !== 'md' ? ' sc-' + size : '');
const styleAttr = color ? ' style="--sc-accent: ' + color + '; --sc-lip: ' + color + ';"' : '';
let html = '<span class="' + cls + '"' + styleAttr + '>';
parts.forEach(function (key, index) {
  if (index > 0) html += '<span class="shortcut-plus">' + esc(sep) + '</span>';
  html += '<kbd class="shortcut-key">' + esc(key) + '</kbd>';
});
html += '</span>';
return html;
